# One turtle per row
turtles = []
for y in range(HEIGHT):
    t = turtle.Turtle()
    t.hideturtle()
    t.penup()
    t.speed(0)
    turtles.append(t)

# Draw column-by-column so all rows draw simultaneously
for x in range(WIDTH):
    for y in range(HEIGHT):
        r, g, b = pixels[y * WIDTH + x]
        t = turtles[y]
        t.goto(START_X + x * PIXEL, START_Y - y * PIXEL)
        t.dot(PIXEL, (r, g, b))
    screen.update()

turtle.done()
